export function format(first?: string, middle?: string, last?: string): string {
  return (first || '') + (middle != null && middle !== '' ? ` ${middle}` : '') + (last != null && last !== '' ? ` ${last}` : '');
}

export const forwardCommonHostAttributes = (el: HTMLElement) => forwardHostAttributes(el, ['type', 'disabled']);

export function forwardHostAttributes(el: HTMLElement, ignore: string[] = []): { [key: string]: string } {
  const result: Record<string, string> = {};

  for (const attr of Array.from(el.attributes)) {
    if (!ignore.includes(attr.name)) {
      result[attr.name] = attr.value;
    }
  }

  return result;
}

