/**
 * Creates a native Event or CustomEvent depending on whether `detail` is provided.
 * Works in browsers and Jest/JSDOM (falls back to `document.createEvent`).
 */
export function createEvent<T = unknown>(
  type: string,
  options?: {
    bubbles?: boolean;
    cancelable?: boolean;
    composed?: boolean;
    detail?: T;
  },
): T extends undefined ? Event : CustomEvent<T> {
  const { bubbles = true, cancelable = true, composed = true, detail } = options ?? {};

  // Modern environments
  if (typeof CustomEvent === 'function') {
    if (detail !== undefined) {
      return new CustomEvent<T>(type, { detail, bubbles, cancelable, composed }) as any;
    }

    return new Event(type, { bubbles, cancelable, composed }) as any;
  }

  // Fallback: legacy or limited JSDOM env
  if (typeof document !== 'undefined' && document.createEvent) {
    if (detail !== undefined) {
      const evt = document.createEvent('CustomEvent');
      (evt as CustomEvent<T>).initCustomEvent(type, bubbles, cancelable, detail);

      return evt as any;
    }
    const evt = document.createEvent('Event');
    evt.initEvent(type, bubbles, cancelable);

    return evt as any;
  }

  throw new Error('Event creation not supported in this environment');
}

